import React, { useMemo, type JSX } from "react";
import type { SeriesMarker, Time, UTCTimestamp } from "lightweight-charts";
import KlineChart from "./KlineChart";
import { parseHeightPx } from "./klineUtil";
import {
  getJellyAnchorIndex,
  getJellyAnchorRow,
  getJellyChartWindow,
  getJellyHlDelistIndex,
  getJellyPriceSourceLabel,
  getJellyRow,
  isJellyHlDelistFrame,
  jellyRowsToCandles,
} from "../../../offline/mock_data/jellyevent";
import { useOptionalJellyMode } from "../../context/JellyModeContext";
import { TERMINAL_COLORS } from "../../constants/terminalColors";
import "./finchart.css";

export interface JellyKlineChartWidgetProps {
  height?: string;
  className?: string;
}

function JellyKlineChartWidget({
  height,
  className = "",
}: JellyKlineChartWidgetProps): JSX.Element {
  const jellyCtx = useOptionalJellyMode();
  const frameIndex = jellyCtx?.frameIndex ?? getJellyAnchorIndex();
  const replayPhase = jellyCtx?.replayPhase ?? "intro";

  const candles = useMemo(() => {
    const window = getJellyChartWindow(frameIndex);
    return jellyRowsToCandles(window);
  }, [frameIndex]);

  const delistMarker = useMemo((): SeriesMarker<Time>[] => {
    const delistIndex = getJellyHlDelistIndex();
    if (delistIndex < 0) return [];
    const delistRow = getJellyRow(delistIndex);
    if (!delistRow) return [];
    const time = Math.floor(new Date(delistRow.snapshotTime).getTime() / 1000) as UTCTimestamp;
    return [
      {
        time,
        position: "aboveBar",
        shape: "circle",
        color: TERMINAL_COLORS.warning,
        text: "HL delist",
      },
    ];
  }, []);

  const currentRow = getJellyChartWindow(frameIndex).at(-1);
  const anchorRow = getJellyAnchorRow();
  const anchorPrice = anchorRow.priceHL;

  const statusLabel = useMemo(() => {
    if (!currentRow) return "JELLY-USDT";
    const sourceTag = getJellyPriceSourceLabel(currentRow);
    if (replayPhase === "intro") {
      return `${currentRow.date} ${currentRow.time} · Pre-crash · ${sourceTag} · JELLY-USDT`;
    }
    if (replayPhase === "finished") {
      return `${currentRow.date} ${currentRow.time} · Crash complete · ${sourceTag} · JELLY-USDT`;
    }
    const pct =
      anchorPrice > 0
        ? (((currentRow.priceHL - anchorPrice) / anchorPrice) * 100).toFixed(1)
        : "0.0";
    if (isJellyHlDelistFrame(frameIndex)) {
      return `${currentRow.date} ${currentRow.time} · HL delist · ${pct}% · JELLY-USDT`;
    }
    if (currentRow.priceSource === "binance") {
      return `${currentRow.date} ${currentRow.time} · Replaying · ${pct}% · ${sourceTag} · JELLY-USDT`;
    }
    return `${currentRow.date} ${currentRow.time} · Replaying · ${pct}% · ${sourceTag} · JELLY-USDT`;
  }, [currentRow, replayPhase, anchorPrice, frameIndex]);

  return (
    <div
      className={`kline-chart-widget jelly-kline-chart-widget ${className}`.trim()}
      style={{
        width: "100%",
        height: "100%",
        minHeight: parseHeightPx(height),
      }}
    >
      <div className="kline-chart-widget-body">
        <KlineChart
          symbol="JELLY-USDT"
          initialData={candles}
          resetScrollKey={String(frameIndex)}
          seedScrollMode="fit"
          markers={delistMarker}
        />
      </div>
      <div className="kline-chart-status kline-chart-status--overlay terminal-label kline-chart-status--compact">
        {statusLabel}
      </div>
    </div>
  );
}

export default JellyKlineChartWidget;
